    class Solution:
        def reverseParentheses(self, s: str) -> str:
            stack = [[]]
            for char in s:
                if char == '(':
                    stack.append([])
                elif char == ')':
                    last = stack.pop()
                    last.reverse()
                    stack[-1].extend(last)
                else:
                    stack[-1].append(char)
            return ''.join(stack[0])

